checker_dsl:
EXISTS (`VarAccess VA`, `SsaSourceVariable V`) {
  EXISTS (`BasicBlock BB`, `SsaDefinition SSA`) {
    AND {
      (`V is not an instance of Field`),
      (`SSA is the source variable definition for V`),
      NOT { (`a null-guard for SSA being non-null controls the entry to BB`) },
      EXISTS (`ControlFlowNode N`) {
        AND {
          (`N is a dereference of the value represented by SSA at access point VA`),
          (`N belongs to basic block BB`),
          (`N is the first node in BB that is a dereference of the value represented by SSA`)
        }
      },
      OR {
        FORALL (`SsaDefinition DEF`) {
          AND {
            (`DEF is an ultimate definition of SSA`),
            (`DEF is an explicit write whose assigned value is an expression that is always null`)
          }
        },
        AND {
          (`a null-guard for SSA being null controls the entry to BB`),
          NOT { (`SSA is clearly known to be non-null`) }
        }
      }
    }
  }
}
